const cellKey = ([x, y]: Cell): string => `${x},${y}`;
const parseCell = (key: string): Cell => {
  const [x, y] = key.split(",").map(Number);
  return [x, y];
};

function countNeighbors(livingCells: Cell[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const [x, y] of livingCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const key = cellKey([x + dx, y + dy]);
      counts.set(key, (counts.get(key) ?? 0) + 1);
    }
  }
  return counts;
}

const survives = (count: number, wasAlive: boolean): boolean =>
  count === 3 || (count === 2 && wasAlive);

export function nextGeneration(livingCells: Cell[]): Cell[] {
  const liveSet = new Set(livingCells.map(cellKey));
  return Array.from(countNeighbors(livingCells))
    .filter(([key, count]) => survives(count, liveSet.has(key)))
    .map(([key]) => parseCell(key));
}

